<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Desktop</title>
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
body{overflow:hidden;width:100vw;height:100vh;font-family:'Segoe UI',system-ui,sans-serif;}

#desktop{
  width:100vw;height:100vh;position:relative;overflow:hidden;
  background:
    radial-gradient(ellipse 80% 60% at 20% 80%, rgba(124,58,237,.35) 0%, transparent 60%),
    radial-gradient(ellipse 60% 50% at 80% 20%, rgba(220,38,127,.25) 0%, transparent 55%),
    radial-gradient(ellipse 100% 100% at 50% 50%, #1e1b2e 0%, #0d0b1a 100%);
}

/* subtle grid overlay */
#desktop::before{
  content:'';position:absolute;inset:0;
  background-image:linear-gradient(rgba(255,255,255,.02) 1px,transparent 1px),
                   linear-gradient(90deg,rgba(255,255,255,.02) 1px,transparent 1px);
  background-size:40px 40px;pointer-events:none;
}

/* ── TASKBAR ── */
#taskbar{
  position:absolute;bottom:0;left:0;right:0;height:60px;
  background:rgba(15,12,28,.88);backdrop-filter:blur(24px);
  border-top:1px solid rgba(255,255,255,.07);
  display:flex;align-items:center;justify-content:center;gap:10px;
  z-index:500;
}

.launcher-btn{
  width:46px;height:46px;border-radius:13px;border:none;
  cursor:pointer;display:flex;align-items:center;justify-content:center;
  font-size:22px;transition:transform .15s,box-shadow .15s;
  position:relative;
}
.launcher-btn::after{
  content:'';position:absolute;bottom:-8px;left:50%;transform:translateX(-50%);
  width:4px;height:4px;border-radius:50%;background:#7c3aed;
  opacity:0;transition:opacity .15s;
}
.launcher-btn.active::after{opacity:1;}
#open-files{background:linear-gradient(135deg,#f59e0b,#ef4444);}
#open-notepad{background:linear-gradient(135deg,#3b82f6,#8b5cf6);}
.launcher-btn:hover{transform:translateY(-5px);box-shadow:0 10px 28px rgba(0,0,0,.5);}
.launcher-btn:active{transform:translateY(-2px);}

/* ── WINDOW BASE ── */
.window{
  position:absolute;
  min-width:360px;min-height:240px;
  background:#1e1c2e;
  border-radius:11px;
  box-shadow:0 24px 64px rgba(0,0,0,.7),0 0 0 1px rgba(255,255,255,.07);
  display:flex;flex-direction:column;overflow:hidden;
  transition:box-shadow .15s;
}
.window:focus-within{box-shadow:0 28px 72px rgba(0,0,0,.75),0 0 0 1px rgba(124,58,237,.35);}

.titlebar{
  height:38px;background:#2a2640;
  display:flex;align-items:center;padding:0 12px;
  cursor:move;user-select:none;flex-shrink:0;
  border-bottom:1px solid rgba(0,0,0,.4);gap:8px;
}
.tbar-btns{display:flex;gap:6px;align-items:center;}
.win-close{
  width:13px;height:13px;border-radius:50%;
  background:#ff5f57;border:none;cursor:pointer;
  display:flex;align-items:center;justify-content:center;
  font-size:0;color:#820000;transition:font-size .1s;flex-shrink:0;
}
.win-close:hover{font-size:8px;}
.tbar-min,.tbar-max{
  width:13px;height:13px;border-radius:50%;border:none;cursor:pointer;
}
.tbar-min{background:#febc2e;}
.tbar-max{background:#28c840;}
.tbar-title{
  flex:1;text-align:center;font-size:12.5px;font-weight:500;
  color:#b0a8cc;letter-spacing:.3px;padding-right:39px;
}

.win-body{flex:1;display:flex;flex-direction:column;overflow:hidden;}

/* ── FILES WINDOW ── */
#files-window{width:580px;height:420px;top:70px;left:60px;}

#files-toolbar{
  display:flex;align-items:center;gap:8px;
  padding:7px 10px;background:#201d30;
  border-bottom:1px solid #111;flex-shrink:0;
}
#files-up{
  width:30px;height:30px;border-radius:7px;
  background:#3a3555;border:1px solid #4a4470;
  color:#b0a8cc;cursor:pointer;font-size:15px;
  display:flex;align-items:center;justify-content:center;
  flex-shrink:0;transition:background .1s;
}
#files-up:hover{background:#4a4570;}
#files-path{
  flex:1;background:#141220;border:1px solid #3a3555;
  border-radius:7px;padding:5px 10px;color:#d0c8f0;
  font-size:12px;font-family:monospace;
  white-space:nowrap;overflow:hidden;text-overflow:ellipsis;
}
#files-list{
  flex:1;overflow-y:auto;padding:10px;
  display:flex;flex-wrap:wrap;align-content:flex-start;gap:2px;
  background:#181626;
}
.fs-item{
  width:82px;padding:8px 4px 6px;border-radius:7px;
  cursor:pointer;display:flex;flex-direction:column;
  align-items:center;gap:5px;text-align:center;
  color:#c0b8e0;font-size:11.5px;transition:background .12s;
  word-break:break-all;
}
.fs-item:hover{background:rgba(124,58,237,.18);}
.fs-item.selected{background:rgba(124,58,237,.3);}
.fs-item-icon{font-size:30px;line-height:1;display:block;}

/* ── NOTEPAD WINDOW ── */
#notepad-window{width:620px;height:460px;top:90px;left:160px;}

#tabs-bar{
  display:flex;align-items:stretch;
  background:#141220;border-bottom:1px solid #0d0b18;
  flex-shrink:0;overflow:hidden;
}
#tabs{display:flex;flex:1;overflow-x:auto;overflow-y:hidden;}
#tabs::-webkit-scrollbar{height:3px;}
#tabs::-webkit-scrollbar-thumb{background:#4a4570;}

.tab{
  padding:9px 14px;background:#1a1728;
  border:none;color:#7a7299;cursor:pointer;
  font-size:12px;white-space:nowrap;
  border-right:1px solid #0d0b18;
  border-bottom:2px solid transparent;
  transition:background .12s,color .12s;
  display:flex;align-items:center;gap:6px;
  flex-shrink:0;min-width:90px;max-width:160px;
}
.tab:hover{background:#221f35;color:#b0a8cc;}
.tab.active{background:#1e1c2e;color:#e0d8ff;border-bottom-color:#7c3aed;}
.tab-name{flex:1;overflow:hidden;text-overflow:ellipsis;text-align:left;}
.tab-x{
  opacity:0;font-size:11px;line-height:1;color:#7a7299;
  transition:opacity .1s;flex-shrink:0;
  background:none;border:none;cursor:pointer;padding:0;color:inherit;
}
.tab:hover .tab-x,.tab.active .tab-x{opacity:.7;}
.tab-x:hover{opacity:1 !important;}
#new-tab{
  padding:0 14px;background:transparent;border:none;
  color:#5a5282;cursor:pointer;font-size:18px;flex-shrink:0;
  transition:color .12s,background .12s;
}
#new-tab:hover{color:#c0b8e0;background:#221f35;}

#editor{
  flex:1;resize:none;border:none;outline:none;
  background:#13111f;color:#d4cfed;
  padding:14px;font-family:'Courier New',Courier,monospace;
  font-size:13.5px;line-height:1.65;
}
#editor::placeholder{color:#3a3555;}

/* scrollbars */
::-webkit-scrollbar{width:6px;height:6px;}
::-webkit-scrollbar-track{background:transparent;}
::-webkit-scrollbar-thumb{background:#3a3555;border-radius:3px;}
::-webkit-scrollbar-thumb:hover{background:#5a5282;}
</style>
