  </div>

</div>
<script>
// ═══════════════════════════════════════════════
//  FILESYSTEM
// ═══════════════════════════════════════════════
const FS = {
  '/':                                  {dir:true, kids:['bin','etc','home','usr','var','tmp','dev','opt','proc']},
  '/bin':                               {dir:true, kids:['bash','sh','ls','cp','mv','rm','cat','grep','find','chmod','chown']},
