  '/home':                              {dir:true, kids:['user']},
  '/home/user':                         {dir:true, kids:['Documents','Downloads','Pictures','Desktop','Music','.bashrc','.profile','.ssh']},
  '/home/user/.ssh':                    {dir:true, kids:['id_rsa','id_rsa.pub','authorized_keys','config']},
  '/home/user/Documents':              {dir:true, kids:['resume.pdf','notes.txt','budget.xlsx','todo.md','Projects']},
  '/home/user/Documents/Projects':     {dir:true, kids:['website','scripts','data-analysis']},
  '/home/user/Documents/Projects/website':      {dir:true, kids:['index.html','style.css','app.js','README.md']},
  '/home/user/Documents/Projects/scripts':      {dir:true, kids:['backup.sh','deploy.sh','cleanup.py','cron_jobs.sh']},
  '/home/user/Documents/Projects/data-analysis':{dir:true, kids:['notebook.ipynb','data.csv','results.json','plots']},
  '/home/user/Documents/Projects/data-analysis/plots':{dir:true, kids:['histogram.png','scatter.svg','trend.png']},
  '/home/user/Downloads':              {dir:true, kids:['ubuntu-24.04.iso','archive.tar.gz','photo.jpg','setup.deb','movie.mp4']},
  '/home/user/Pictures':               {dir:true, kids:['wallpapers','screenshots','vacation.jpg','profile.png']},
  '/home/user/Pictures/wallpapers':    {dir:true, kids:['dark_mountains.png','aurora.jpg','abstract.png','minimal.png']},
  '/home/user/Pictures/screenshots':   {dir:true, kids:['2025-01-15.png','2025-03-02.png','2025-06-20.png']},
  '/home/user/Desktop':                {dir:true, kids:['terminal.desktop','browser.desktop']},
  '/home/user/Music':                  {dir:true, kids:['playlist.m3u','lofi_session.mp3','focus_mix.flac']},
  '/usr':                               {dir:true, kids:['bin','lib','local','share','include','sbin']},
