  '/var/log/nginx':                     {dir:true, kids:['access.log','error.log']},
  '/var/log/apt':                       {dir:true, kids:['history.log','term.log']},
  '/var/cache':                         {dir:true, kids:['apt','fontconfig','man']},
  '/var/cache/apt':                     {dir:true, kids:['archives','pkgcache.bin']},
  '/var/lib':                           {dir:true, kids:['apt','dpkg','docker','postgresql']},
  '/var/www':                           {dir:true, kids:['html']},
  '/var/www/html':                      {dir:true, kids:['index.html','about.html','assets']},
  '/var/www/html/assets':              {dir:true, kids:['style.css','app.js','logo.svg']},
  '/tmp':                               {dir:true, kids:['session_a1b2','tmpfile.txt','snap-private-tmp']},
  '/dev':                               {dir:true, kids:['null','zero','random','urandom','sda','sda1','sda2','tty','pts']},
  '/opt':                               {dir:true, kids:['google','sublime-text','jetbrains']},
  '/opt/google':                        {dir:true, kids:['chrome']},
  '/opt/google/chrome':                {dir:true, kids:['chrome','chrome.desktop','libEGL.so']},
  '/opt/jetbrains':                     {dir:true, kids:['idea','pycharm']},
  '/proc':                              {dir:true, kids:['cpuinfo','meminfo','version','uptime','1','42','1337']},
};

function isDir(path){ return FS[path] && FS[path].dir; }

function fileIcon(name, dir){
  if(dir) return '📁';
  const ext = name.split('.').pop().toLowerCase();
  const map={
    sh:'⚙️',bash:'⚙️',py:'🐍',js:'📜',ts:'📜',go:'🔵',
    html:'🌐',css:'🎨',svg:'🎨',
    json:'📋',toml:'📋',yaml:'📋',yml:'📋',
    txt:'📄',md:'📝',pdf:'📕',doc:'📝',docx:'📝',
    xlsx:'📊',csv:'📊',ipynb:'📊',
    jpg:'🖼️',jpeg:'🖼️',png:'🖼️',gif:'🖼️',webp:'🖼️',
    mp3:'🎵',flac:'🎵',wav:'🎵',m3u:'🎵',
    mp4:'🎬',mkv:'🎬',avi:'🎬',
    zip:'📦',tar:'📦',gz:'📦',bz2:'📦',deb:'📦',
    iso:'💿',img:'💿',
    conf:'⚙️',cfg:'⚙️',log:'📋',list:'📋',
    desktop:'🔗',pub:'🔑',pem:'🔑',
    h:'🔧',so:'🔧',
    sql:'🗄️',db:'🗄️',
  };
  return map[ext]||'📄';
}

let currentPath='/';

function renderFiles(){
  document.getElementById('files-path').textContent=currentPath;
  const list=document.getElementById('files-list');
  list.innerHTML='';
  const entry=FS[currentPath];
  if(!entry||!entry.kids) return;
  entry.kids.forEach(name=>{
    const full=currentPath==='/'?'/'+name:currentPath+'/'+name;
    const dir=isDir(full);
    const el=document.createElement('div');
    el.className='fs-item';
    el.dataset.path=full;
    el.innerHTML=`<span class="fs-item-icon">${fileIcon(name,dir)}</span><span>${name}</span>`;
    el.onclick=()=>{
      list.querySelectorAll('.fs-item').forEach(i=>i.classList.remove('selected'));
      el.classList.add('selected');
    };
    if(dir){
      el.ondblclick=()=>{currentPath=full;renderFiles();};
    }
    list.appendChild(el);
  });
}

document.getElementById('files-up').onclick=()=>{
  if(currentPath==='/') return;
  const parts=currentPath.split('/').filter(Boolean);
  parts.pop();
  currentPath=parts.length?'/'+parts.join('/'):'/' ;
  renderFiles();
};

// ═══════════════════════════════════════════════
//  NOTEPAD  (localStorage persistence)
// ═══════════════════════════════════════════════
const STORE='__desktop_notepad__';
let tabs=[], activeId=null;

function uid(){ return 't'+Date.now().toString(36)+Math.random().toString(36).slice(2,6); }

function persist(){
  localStorage.setItem(STORE,JSON.stringify({tabs,activeId}));
}

function hydrate(){
  try{
    const d=JSON.parse(localStorage.getItem(STORE)||'null');
    if(d&&Array.isArray(d.tabs)&&d.tabs.length){
      tabs=d.tabs;
      activeId=d.activeId&&tabs.find(t=>t.id===d.activeId)?d.activeId:tabs[0].id;
      return;
    }
  }catch(_){}
  const id=uid();
  tabs=[{id,name:'Untitled 1',text:''}];
  activeId=id;
}

function flushEditor(){
  const t=tabs.find(t=>t.id===activeId);
  if(t) t.text=document.getElementById('editor').value;
}

function renderNotepad(){
  const strip=document.getElementById('tabs');
  strip.innerHTML='';
  tabs.forEach(t=>{
    const btn=document.createElement('button');
    btn.className='tab'+(t.id===activeId?' active':'');
    btn.dataset.id=t.id;
    btn.innerHTML=`<span class="tab-name">${escHtml(t.name)}</span><button class="tab-x" data-xid="${t.id}" title="Close">✕</button>`;
    btn.onclick=e=>{
      const xid=e.target.closest('[data-xid]')&&e.target.closest('[data-xid]').dataset.xid;
      if(xid){closeTab(xid);return;}
      flushEditor();
      activeId=t.id;
      renderNotepad();
      persist();
    };
    strip.appendChild(btn);
  });
  const active=tabs.find(t=>t.id===activeId);
  document.getElementById('editor').value=active?active.text:'';
}

function closeTab(id){
  flushEditor();
  const idx=tabs.findIndex(t=>t.id===id);
  if(idx===-1) return;
  tabs.splice(idx,1);
  if(!tabs.length){
    const nid=uid(); tabs=[{id:nid,name:'Untitled 1',text:''}]; activeId=nid;
  } else if(activeId===id){
    activeId=tabs[Math.min(idx,tabs.length-1)].id;
  }
  renderNotepad(); persist();
}

document.getElementById('new-tab').onclick=()=>{
  flushEditor();
  const num=tabs.length+1;
  const nid=uid();
  tabs.push({id:nid,name:'Untitled '+num,text:''});
  activeId=nid;
  renderNotepad(); persist();
  document.getElementById('editor').focus();
};

document.getElementById('editor').oninput=()=>{flushEditor();persist();};

function escHtml(s){ return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

// ═══════════════════════════════════════════════
//  WINDOW MANAGEMENT
// ═══════════════════════════════════════════════
let zCounter=10;

function bringToFront(win){win.style.zIndex=++zCounter;}

function openWindow(id){
  const win=document.getElementById(id);
  win.style.display='flex';
  bringToFront(win);
  if(id==='files-window') renderFiles();
  if(id==='notepad-window') renderNotepad();
  document.getElementById(id==='files-window'?'open-files':'open-notepad').classList.add('active');
}

function closeWindow(id){
  document.getElementById(id).style.display='none';
  document.getElementById(id==='files-window'?'open-files':'open-notepad').classList.remove('active');
}

document.getElementById('open-files').onclick=()=>{
  const w=document.getElementById('files-window');
  if(w.style.display==='none') openWindow('files-window');
  else bringToFront(w);
};
document.getElementById('open-notepad').onclick=()=>{
  const w=document.getElementById('notepad-window');
  if(w.style.display==='none') openWindow('notepad-window');
  else bringToFront(w);
};

// Close buttons
document.querySelectorAll('.win-close').forEach(btn=>{
  btn.onclick=()=>closeWindow(btn.dataset.wid);
});

// Click to raise
document.querySelectorAll('.window').forEach(win=>{
  win.addEventListener('mousedown',()=>bringToFront(win),true);
});

// ── Drag ──
document.querySelectorAll('.titlebar').forEach(bar=>{
  let dragging=false, ox=0,oy=0, sx=0,sy=0;
  const win=bar.closest('.window');
  bar.addEventListener('mousedown',e=>{
    if(e.target.closest('button')) return;
    dragging=true;
    const r=win.getBoundingClientRect();
    ox=r.left; oy=r.top; sx=e.clientX; sy=e.clientY;
    bringToFront(win);
    e.preventDefault();
  });
  document.addEventListener('mousemove',e=>{
    if(!dragging) return;
    const dx=e.clientX-sx, dy=e.clientY-sy;
    const dw=document.getElementById('desktop');
    const dwr=dw.getBoundingClientRect();
    const wr=win.getBoundingClientRect();
    let nx=ox+dx, ny=oy+dy;
    nx=Math.max(dwr.left, Math.min(nx, dwr.right-wr.width));
    ny=Math.max(dwr.top, Math.min(ny, dwr.bottom-40));
    win.style.left=nx+'px';
    win.style.top=ny+'px';
  });
  document.addEventListener('mouseup',()=>{dragging=false;});
});

// ── Touch drag support ──
document.querySelectorAll('.titlebar').forEach(bar=>{
  let dragging=false, ox=0,oy=0, sx=0,sy=0;
  const win=bar.closest('.window');
  bar.addEventListener('touchstart',e=>{
    if(e.target.closest('button')) return;
    dragging=true;
    const r=win.getBoundingClientRect();
    ox=r.left; oy=r.top;
    sx=e.touches[0].clientX; sy=e.touches[0].clientY;
    bringToFront(win);
  },{passive:true});
  document.addEventListener('touchmove',e=>{
    if(!dragging) return;
    const dx=e.touches[0].clientX-sx, dy=e.touches[0].clientY-sy;
    win.style.left=(ox+dx)+'px';
    win.style.top=(oy+dy)+'px';
  },{passive:true});
  document.addEventListener('touchend',()=>{dragging=false;});
});

